package com.wjx871.population.keypopulation;import com.wjx871.population.application.*;import com.wjx871.population.common.BusinessException;import com.wjx871.population.material.ApplicationMaterialMapper;import com.wjx871.population.security.DataScopeCriteria;import java.util.*;import lombok.RequiredArgsConstructor;import org.springframework.http.HttpStatus;import org.springframework.stereotype.Component;
@Component@RequiredArgsConstructor class KeyPopulationWorkflow implements ApplicationSubmissionValidator,ApplicationStatusListener{private final KeyPopulationMapper mapper;private final ApplicationMaterialMapper materials;
public boolean supports(BusinessType t){return t==BusinessType.KEY_POPULATION_REGISTER||t==BusinessType.KEY_POPULATION_RELEASE;}public void validate(BusinessApplication a){KeyPopulationApplication d=mapper.findApplication(a.getApplicationId()).orElseThrow(()->bad("重点人口申请详情不存在"));mapper.personScopedStatus(d.getPersonId(),DataScopeCriteria.current()).orElseThrow(()->new BusinessException(HttpStatus.FORBIDDEN,"超出人员数据范围"));Set<String> types=new HashSet<>();materials.selectByApplicationId(a.getApplicationId()).stream().filter(x->Boolean.TRUE.equals(x.getRequiredFlag())).forEach(x->types.add(x.getMaterialType()));if(!types.contains("KEY_POPULATION_BASIS")||!types.contains("SITUATION_DESCRIPTION"))throw conflict("缺少重点人口登记依据或情况说明材料");}
public void onStatusChanged(BusinessApplication a,ApplicationStatus s){KeyPopulationApplication d=mapper.findApplication(a.getApplicationId()).orElse(null);if(d==null)return;KeyApplicationStatus to=switch(s){case UNDER_REVIEW,SUBMITTED->KeyApplicationStatus.UNDER_REVIEW;case APPROVED->KeyApplicationStatus.APPROVED;case REJECTED->KeyApplicationStatus.REJECTED;case WITHDRAWN,CANCELLED->KeyApplicationStatus.WITHDRAWN;default->null;};if(to!=null&&mapper.updateApplicationStatus(a.getApplicationId(),d.getBusinessStatus(),to,d.getVersion())==0)ApplicationService.conflict();}private BusinessException bad(String m){return new BusinessException(HttpStatus.BAD_REQUEST,m);}private BusinessException conflict(String m){return new BusinessException(HttpStatus.CONFLICT,m);}}
